-- 6he7.lua
-- Luraph v14.7 Deobfuscator - Delta Executor
-- MODE = 1: Patch VM dispatch loop -> dump state (default)
-- MODE = 2: Hook h9 -> trace execution
-- MODE = 3: Run normally (no hooks)
-- MODE = 4: Capture only (bytecode + VM source)
-- MODE = 5: All approaches (A+B+C)

local MODE = 1

-- ===== OUTPUT CAPTURE =====
local _out = {}
local _oprint = print
local function _print(...)
  local t = {}
  for i = 1, select("#", ...) do t[i] = tostring(select(i, ...)) end
  local line = table.concat(t, "\t")
  _out[#_out + 1] = line
  _oprint(line)
end
print = _print

-- ===== SAFE HOOK HELPER =====
local function safe_hook(tbl, key, hook_fn)
  local orig = tbl[key]
  if not orig then return false, "no original" end
  if hookfunction then
    local ok = pcall(hookfunction, orig, hook_fn)
    if ok then return true, "hookfunction" end
  end
  local ok, err = pcall(function()
    tbl[key] = hook_fn
  end)
  if ok then
    -- Wrap hook_fn to call orig
    tbl[key] = function(...) return hook_fn(orig, ...) end
    return true, "direct"
  end
  return false, err or "cannot hook"
end

-- ===== DUMP CODE (inserted into VM source) =====
local DUMP_CODE = [=[
  print("=== VM STATE DUMP ===")
  print("S (opcode index): " .. tostring(S))
  print("")
  print("--- STATE TABLE j ---")
  local _n = 0
  for _k, _v in pairs(j) do
    _n = _n + 1
    if _n <= 2000 then
      local _t = type(_v)
      if _t == "number" then
        print("j[" .. tostring(_k) .. "] = " .. tostring(_v))
      elseif _t == "string" then
        print("j[" .. tostring(_k) .. "] = " .. string.format("%q", _v:sub(1, 300)))
      elseif _t == "boolean" then
        print("j[" .. tostring(_k) .. "] = " .. tostring(_v))
      elseif _t == "function" then
        print("j[" .. tostring(_k) .. "] = function")
      elseif _t == "table" then
        local _cnt = 0
        for _ in pairs(_v) do _cnt = _cnt + 1 end
        local _sc = 0
        local _isnum = true
        for _k2, _v2 in ipairs(_v) do
          _sc = _sc + 1
          if _sc <= 10 and type(_v2) ~= "number" then _isnum = false break end
        end
        if _isnum and _sc > 10 then
          local _line = "j[" .. tostring(_k) .. "] = num_array(" .. _sc .. "+): "
          for _k2, _v2 in ipairs(_v) do
            if _k2 <= 200 then
              _line = _line .. tostring(_v2) .. ","
            else
              break
            end
          end
          print(_line)
        else
          print("j[" .. tostring(_k) .. "] = table(" .. _cnt .. " entries)")
          local _ec = 0
          for _k2, _v2 in pairs(_v) do
            _ec = _ec + 1
            if _ec <= 50 then
              print("  [" .. tostring(_k2) .. "] = " .. type(_v2) .. " " .. tostring(_v2):sub(1, 200))
            end
          end
        end
      else
        print("j[" .. tostring(_k) .. "] = " .. _t)
      end
    end
  end
  print("Total j keys: " .. _n)
  print("")
  print("--- VM TABLE a ---")
  local _mn = 0
  for _k, _v in pairs(a) do
    _mn = _mn + 1
    if _mn <= 300 then
      print("a." .. tostring(_k) .. " = " .. type(_v))
    end
  end
  print("Total a keys: " .. _mn)
  print("")
  if a.A then
    print("--- VM CONSTANTS a.A ---")
    for _k, _v in pairs(a.A) do
      print("a.A[" .. tostring(_k) .. "] = " .. tostring(_v))
    end
  end
  print("")
  if a.V then
    print("--- VM BITOPS a.V ---")
    for _k, _v in pairs(a.V) do
      print("a.V." .. tostring(_k) .. " = " .. type(_v))
    end
  end
  print("")
  print("=== DUMP DONE ===")
  error("DUMP_DONE")
]=]

-- ===== HOOKS =====
local _ols = loadstring
local _obfs = buffer and buffer.fromstring or nil
local _cap_vm = nil
local _cap_bc = nil

-- Hook buffer.fromstring
if _obfs then
  local _hook_ok, _hook_err = pcall(function()
    buffer.fromstring = function(s)
      if #s > 100000 then
        _cap_bc = s
        print("[CAP] buffer.fromstring: " .. #s .. " bytes")
        local hex = ""
        for i = 1, math.min(512, #s) do
          hex = hex .. string.format("%02x", string.byte(s, i))
        end
        print("[CAP] hex(0..255): " .. hex)
      end
      return _obfs(s)
    end
  end)
  if not _hook_ok then
    print("[HOOK] buffer.fromstring hook failed: " .. tostring(_hook_err))
    -- Try hookfunction
    if hookfunction then
      local hf_ok = pcall(hookfunction, _obfs, function(s)
        if #s > 100000 then
          _cap_bc = s
          print("[CAP] buffer.fromstring (hf): " .. #s .. " bytes")
        end
        return _obfs(s)
      end)
      if hf_ok then print("[HOOK] buffer.fromstring hooked via hookfunction") end
    end
  else
    print("[HOOK] buffer.fromstring hooked")
  end
end

-- Hook loadstring
local _ls_hook_ok = pcall(function()
  loadstring = function(src, cn, ...)
    if src and type(src) == "string" and #src > 10000 then
      if src:find("h9") then
        _cap_vm = src
        print("[CAP] loadstring: VM source (" .. #src .. " bytes)")
        
        if MODE == 1 or MODE == 5 then
          local pos = src:find("S=76;while true do")
          if pos then
            src = src:sub(1, pos - 1) .. "do " .. DUMP_CODE .. " end;" .. src:sub(pos)
            print("[HOOK] VM patched: dump at pos " .. pos)
          else
            pos = src:find("while true do S,x,p=a:h9")
            if pos then
              src = src:sub(1, pos - 1) .. "do " .. DUMP_CODE .. " end; " .. src:sub(pos)
              print("[HOOK] VM patched (alt) at pos " .. pos)
            else
              print("[HOOK] WARNING: dispatch loop not found!")
            end
          end
        elseif MODE == 2 then
          local pos = src:find("S=76;while true do")
          if pos then
            local trace = [=[
              local _tc = 0
              local _oh = a.h9
              a.h9 = function(...)
                _tc = _tc + 1
                if _tc <= 10000 then
                  local args = {...}
                  print("[TRACE] " .. _tc .. " S=" .. tostring(args[1]))
                end
                if _tc >= 50000 then
                  print("[TRACE] limit reached")
                  error("TRACE_DONE")
                end
                return _oh(...)
              end
            ]=]
            src = src:sub(1, pos - 1) .. "do " .. trace .. " end;" .. src:sub(pos)
            print("[HOOK] VM patched: trace mode")
          end
        end
        
        return _ols(src, cn or "Luraph    ", ...)
      end
    end
    return _ols(src, cn, ...)
  end
end)

if not _ls_hook_ok then
  print("[HOOK] loadstring hook failed, trying hookfunction")
  if hookfunction then
    pcall(hookfunction, _ols, function(src, cn, ...)
      if src and type(src) == "string" and #src > 10000 and src:find("h9") then
        _cap_vm = src
        print("[CAP] loadstring (hf): VM source (" .. #src .. " bytes)")
        if MODE == 1 or MODE == 5 then
          local pos = src:find("S=76;while true do")
          if pos then
            src = src:sub(1, pos - 1) .. "do " .. DUMP_CODE .. " end;" .. src:sub(pos)
            print("[HOOK] VM patched via hf: dump at pos " .. pos)
          end
        end
        return _ols(src, cn or "Luraph    ", ...)
      end
      return _ols(src, cn, ...)
    end)
    print("[HOOK] loadstring hooked via hookfunction")
  end
else
  print("[HOOK] loadstring hooked")
end

