-- ===== MAIN =====
print("")
print(string.rep("=", 70))
print("=== 6he7.lua - Luraph v14.7 Deobfuscator ===")
print("=== MODE: " .. tostring(MODE) .. " ===")
print(string.rep("=", 70))
print("")

print("[*] Loading obfuscated script...")
local fn = _ols(OBFUSCATED, "obfuscated")
if not fn then
  print("[!] Failed to load obfuscated script")
else
  print("[*] Running with hooks...")
  local ok, err = pcall(fn)
  if ok then
    print("[*] Script completed normally")
  elseif type(err) == "string" and err:find("DUMP") then
    print("[*] Dump complete!")
  elseif type(err) == "string" and err:find("TRACE") then
    print("[*] Trace complete!")
  else
    print("[!] Error: " .. tostring(err))
  end
end

-- ===== APPROACH B: Direct load with h9 hook =====
if _cap_vm and _cap_bc and (MODE == 1 or MODE == 5) then
  print("")
  print(string.rep("=", 70))
  print("=== APPROACH B: Direct VM load + h9 hook ===")
  print(string.rep("=", 70))
  
  local vm_fn = _ols(_cap_vm, "vm_direct")
  if not vm_fn then
    print("[!] Failed to load VM")
  else
    local buf = _obfs(_cap_bc)
    print("[*] Loading VM module...")
    local vok, vtable = pcall(vm_fn, buf)
    if not vok then
      print("[!] VM load error: " .. tostring(vtable))
    else
      print("[+] VM table type: " .. type(vtable))
      print("[*] VM methods:")
      for k, v in pairs(vtable) do
        print("  " .. tostring(k) .. " = " .. type(v))
      end
      
      local _dumped = false
      local _oh9 = vtable.h9
      if _oh9 then
        vtable.h9 = function(self, S, p, j, X, F, R, ...)
          if not _dumped then
            _dumped = true
            print("")
            print("=== APPROACH B: h9 STATE DUMP ===")
            print("S: " .. tostring(S))
            print("p: " .. type(p))
            print("j: " .. type(j))
            print("X: " .. type(X))
            print("F: " .. type(F))
            print("R: " .. type(R))
            print("")
            if type(j) == "table" then
              local _n = 0
              for _k, _v in pairs(j) do
                _n = _n + 1
                if _n <= 2000 then
                  local _t = type(_v)
                  if _t == "number" then
                    print("j[" .. tostring(_k) .. "] = " .. tostring(_v))
                  elseif _t == "string" then
                    print("j[" .. tostring(_k) .. "] = " .. string.format("%q", _v:sub(1, 300)))
                  elseif _t == "boolean" then
                    print("j[" .. tostring(_k) .. "] = " .. tostring(_v))
                  elseif _t == "function" then
                    print("j[" .. tostring(_k) .. "] = function")
                  elseif _t == "table" then
                    local _cnt = 0
                    for _ in pairs(_v) do _cnt = _cnt + 1 end
                    local _sc = 0
                    local _isnum = true
                    for _k2, _v2 in ipairs(_v) do
                      _sc = _sc + 1
                      if _sc <= 10 and type(_v2) ~= "number" then _isnum = false break end
                    end
                    if _isnum and _sc > 10 then
                      local _line = "j[" .. tostring(_k) .. "] = num_array(" .. _sc .. "+): "
                      for _k2, _v2 in ipairs(_v) do
                        if _k2 <= 200 then
                          _line = _line .. tostring(_v2) .. ","
                        else
                          break
                        end
                      end
                      print(_line)
                    else
                      print("j[" .. tostring(_k) .. "] = table(" .. _cnt .. " entries)")
                      local _ec = 0
                      for _k2, _v2 in pairs(_v) do
                        _ec = _ec + 1
                        if _ec <= 50 then
                          print("  [" .. tostring(_k2) .. "] = " .. type(_v2) .. " " .. tostring(_v2):sub(1, 200))
                        end
                      end
                    end
                  else
                    print("j[" .. tostring(_k) .. "] = " .. _t)
                  end
                end
              end
              print("Total j keys: " .. _n)
            end
            print("")
            print("=== APPROACH B DUMP DONE ===")
            error("DUMP_B_DONE")
          end
          return _oh9(self, S, p, j, X, F, R, ...)
        end
        
        print("[*] Running VM:s()...")
        local ok2, err2 = pcall(function() vtable:s() end)
        if ok2 then
          print("[*] VM:s() completed")
        elseif type(err2) == "string" and err2:find("DUMP") then
          print("[*] Approach B dump complete!")
        else
          print("[!] Approach B error: " .. tostring(err2))
        end
      else
        print("[!] No h9 method found")
      end
    end
  end
end

-- ===== APPROACH C: Capture info =====
if MODE == 4 or MODE == 5 then
  print("")
  print(string.rep("=", 70))
  print("=== APPROACH C: Capture info ===")
  print(string.rep("=", 70))
  if _cap_vm then
    print("[*] VM source: " .. #_cap_vm .. " bytes")
    print("[*] VM first 500 chars:")
    print(_cap_vm:sub(1, 500))
  end
  if _cap_bc then
    print("[*] Bytecode: " .. #_cap_bc .. " bytes")
    local hex = ""
    for i = 1, math.min(1024, #_cap_bc) do
      hex = hex .. string.format("%02x", string.byte(_cap_bc, i))
    end
    print("[*] hex(0..1023): " .. hex)
  end
end

